code.imports:
import { tags } from 'decantr/tags';
import { createSignal, onMount, onDestroy } from 'decantr/state';
import { css } from 'decantr/css';

code.example:
function HorizontalSplit({ left, right, initialSplit = 50 }) {
  const { div } = tags;
  const [split, setSplit] = createSignal(initialSplit);
  const [isDragging, setIsDragging] = createSignal(false);
  let containerRef;

  const handleMouseMove = (e) => {
    if (!isDragging() || !containerRef) return;
    const rect = containerRef.getBoundingClientRect();
    const pct = ((e.clientX - rect.left) / rect.width) * 100;
    setSplit(Math.max(10, Math.min(90, pct)));
  };

  const handleMouseUp = () => setIsDragging(false);

  onMount(() => {
    document.addEventListener('mousemove', handleMouseMove);
    document.addEventListener('mouseup', handleMouseUp);
  });

  onDestroy(() => {
    document.removeEventListener('mousemove', handleMouseMove);
    document.removeEventListener('mouseup', handleMouseUp);
  });

  return div({ ref: (el) => containerRef = el, class: css('_flex _hfull _relative') },
    div({ class: css('term-panel _overflow[auto] _p2'), style: () => `width: ${split()}%` }, left),
    div({
      class: css('_w1 _bgborder _cursor[col-resize] _hover:bg[#555]'),
      onmousedown: () => setIsDragging(true),
      ondblclick: () => setSplit(50)
    }),
    div({ class: css('term-panel _overflow[auto] _p2 _flex1') }, right)
  );
}

