function QuadSplit({ topLeft, topRight, bottomLeft, bottomRight }) {
  const { div } = tags;
  const [hSplit, setHSplit] = createSignal(50);
  const [vSplit, setVSplit] = createSignal(50);

  return div({ class: css('_grid _hfull _gap[1px] _bgborder'), style: () =>
    `grid-template-columns: ${hSplit()}% 1px 1fr; grid-template-rows: ${vSplit()}% 1px 1fr`
  },
    div({ class: css('term-panel _overflow[auto] _p2') }, topLeft),
    div({ class: css('_bgborder _cursor[col-resize]') }),
    div({ class: css('term-panel _overflow[auto] _p2') }, topRight),
    div({ class: css('_bgborder _cursor[row-resize]'), style: 'grid-column: 1 / -1' }),
    div({ class: css('term-panel _overflow[auto] _p2') }, bottomLeft),
    div({ class: css('_bgborder') }),
    div({ class: css('term-panel _overflow[auto] _p2') }, bottomRight)
  );
}

